),
built as (
  select i.recipe_en,
    jsonb_agg(jsonb_build_object(
      'name_en', i.ing_en,
      'name_zh', coalesce(ing.name_zh, i.ing_zh),
      'ingredient_id', ing.id,
      'grams', i.grams
    ) order by i.ord) as items
  from imp i
  left join public.ingredients ing on lower(trim(ing.name_en)) = lower(trim(i.ing_en))
  group by i.recipe_en
),
upd as (
  update public.recipes r
  set items = b.items,
      name_zh = coalesce(r.name_zh, rc.name_zh)
  from built b
  join rec rc on lower(trim(rc.name_en)) = lower(trim(b.recipe_en))
  where lower(trim(r.name_en)) = lower(trim(b.recipe_en))
  returning lower(trim(r.name_en)) as name_key
)
insert into public.recipes(id, name_en, name_zh, items, allergen_ids, owner_id, place_id)
select 'rec_imp_' || substr(md5(lower(trim(rc.name_en))),1,16),
       rc.name_en, rc.name_zh, coalesce(b.items, '[]'::jsonb), '[]'::jsonb, null, null
from (select distinct on (lower(trim(name_en))) name_en, name_zh from rec order by lower(trim(name_en))) rc
left join built b on lower(trim(b.recipe_en)) = lower(trim(rc.name_en))
where not exists (select 1 from public.recipes r where lower(trim(r.name_en)) = lower(trim(rc.name_en)));

-- verify
select count(*) as total_recipes,
       count(*) filter (where exists (select 1 from jsonb_array_elements(items) e where (e->>'grams') is null)) as recipes_missing_grams
from public.recipes;
